// ---- CLINIC HOURS (in LOCAL Toronto time) ----
const CLINIC_HOURS = {
  1: { open: 9, close: 19 }, // Monday
  2: { open: 9, close: 17 }, // Tuesday
  3: { open: 9, close: 17 }, // Wednesday
  4: { open: 9, close: 17 }, // Thursday
  5: null,                   // Friday CLOSED
  6: { open: 9, close: 15 }, // Saturday
  0: null                    // Sunday CLOSED
};

const SLOT_DURATION_DEFAULT = 60; // minutes

// ---- HELPER: Get Toronto local hour/day from a UTC Date ----
function toTorontoComponents(date) {
  const parts = new Intl.DateTimeFormat("en-CA", {
    timeZone: "America/Toronto",
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
    second: "2-digit",
    hour12: false
  }).formatToParts(date);

  const get = (type) => parseInt(parts.find(p => p.type === type).value);
  return {
    year: get("year"),
    month: get("month"),
    day: get("day"),
    hour: get("hour"),
    minute: get("minute"),
    second: get("second")
  };
}

// Get the JS weekday (0=Sun) for a date in Toronto timezone
function torontoDayOfWeek(date) {
  const str = date.toLocaleDateString("en-CA", {
    timeZone: "America/Toronto",
    weekday: "short"
  });
  const map = { Sun: 0, Mon: 1, Tue: 2, Wed: 3, Thu: 4, Fri: 5, Sat: 6 };
  return map[str];
}

// Build a UTC Date that represents a specific Toronto local time
function torontoToUTC(year, month, day, hour, minute) {
  const rough = new Date(Date.UTC(year, month - 1, day, hour, minute, 0));
  const comps = toTorontoComponents(rough);
  const diffHours = comps.hour - hour + (comps.day !== day ? (comps.day > day ? 24 : -24) : 0);
  const adjusted = new Date(rough.getTime() - diffHours * 3600000);
  const verify = toTorontoComponents(adjusted);
  const minDiff = verify.minute - minute;
  return new Date(adjusted.getTime() - minDiff * 60000);
}

// ---- REQUEST DATA ----
