    if (match) {
      const [, yr, mo, dy, hr, mn] = match;
      requestedDT = torontoToUTC(
        parseInt(yr), parseInt(mo), parseInt(dy),
        parseInt(hr || "9"), parseInt(mn || "0")
      );
    } else {
      requestedDT = new Date(raw + "-04:00");
