// ---- CHECK SLOT CONFLICT ----
function slotFree(startUTC, endUTC) {
  for (const b of bookedSlots) {
    if (startUTC < b.end && endUTC > b.start) return false;
  }
  return true;
}

// ---- CHECK CLINIC HOURS (using Toronto local time) ----
function withinClinicHours(startUTC, endUTC) {
  const dayOfWeek = torontoDayOfWeek(startUTC);
  const hours = CLINIC_HOURS[dayOfWeek];
  if (!hours) return false;

  const startLocal = toTorontoComponents(startUTC);
  const endLocal = toTorontoComponents(endUTC);

  const startMinutes = startLocal.hour * 60 + startLocal.minute;
  const endMinutes = endLocal.hour * 60 + endLocal.minute;

  return (
    startMinutes >= hours.open * 60 &&
    endMinutes <= hours.close * 60 &&
    startLocal.day === endLocal.day
  );
}

// ---- FORMAT FOR VOICE RESPONSE ----
function formatSlot(dateUTC) {
  return dateUTC.toLocaleString("en-CA", {
    timeZone: "America/Toronto",
    weekday: "long",
    month: "long",
    day: "numeric",
    hour: "numeric",
    minute: "2-digit",
    hour12: true
  });
}

// ---- FIND 2-3 ALTERNATIVE SLOTS ----
// Steps through the day by duration increments so offered slots never overlap
function findAlternatives(fromUTC) {
  const options = [];
  const fromLocal = toTorontoComponents(fromUTC);

  for (let dayOffset = 0; dayOffset < 14 && options.length < 3; dayOffset++) {
    const currentDate = new Date(Date.UTC(fromLocal.year, fromLocal.month - 1, fromLocal.day + dayOffset));
    const comps = toTorontoComponents(currentDate);
    const realYear = comps.year;
    const realMonth = comps.month;
    const realDay = comps.day;

    const testDate = torontoToUTC(realYear, realMonth, realDay, 9, 0);
    const dayOfWeek = torontoDayOfWeek(testDate);
    const hours = CLINIC_HOURS[dayOfWeek];
    if (!hours) continue;

    const openMinutes = hours.open * 60;
    const closeMinutes = hours.close * 60;

    // Step through day by duration so slots don't overlap
    for (let minuteOfDay = openMinutes; minuteOfDay + duration <= closeMinutes && options.length < 3; minuteOfDay += duration) {
      const h = Math.floor(minuteOfDay / 60);
      const m = minuteOfDay % 60;

      const slotStart = torontoToUTC(realYear, realMonth, realDay, h, m);
      const slotEnd = new Date(slotStart.getTime() + duration * 60000);

      if (slotStart.getTime() <= fromUTC.getTime()) continue;
      if (slotStart.getTime() < Date.now()) continue;

      if (withinClinicHours(slotStart, slotEnd) && slotFree(slotStart, slotEnd)) {
        options.push({
          datetime: slotStart.toISOString(),
          label: formatSlot(slotStart)
        });
      }
    }
  }

  return options;
}

