function extractReasonFromDescription(description) {
  const match = (description || "").match(/Reason:\s*(.+)/i);
  return match ? match[1].trim() : "";
}

function extractReasonFromSummary(summary) {
  if (summary.includes("—")) return summary.split("—").pop().trim();
  if (summary.includes("-")) return summary.split("-").pop().trim();
  return "";
}

// ---- CLINIC HOURS CHECK ----
function withinClinicHours(startUTC, endUTC) {
  const dayOfWeek = torontoDayOfWeek(startUTC);
  const hours = CLINIC_HOURS[dayOfWeek];
  if (!hours) return false;
  const startLocal = toTorontoComponents(startUTC);
  const endLocal = toTorontoComponents(endUTC);
  const startMinutes = startLocal.hour * 60 + startLocal.minute;
  const endMinutes = endLocal.hour * 60 + endLocal.minute;
  return (
    startMinutes >= hours.open * 60 &&
    endMinutes <= hours.close * 60 &&
    startLocal.day === endLocal.day
  );
}

// ---- SLOT CONFLICT CHECK ----
function slotFree(startUTC, endUTC, bookedSlots, excludeEventId) {
  for (const b of bookedSlots) {
    if (b.id === excludeEventId) continue;
    if (startUTC < b.end && endUTC > b.start) return false;
  }
  return true;
}

// ---- FIND ALTERNATIVES ----
function findAlternatives(fromUTC, duration, bookedSlots, excludeEventId) {
  const options = [];
  const fromLocal = toTorontoComponents(fromUTC);
  const stepMinutes = duration;

  for (let dayOffset = 0; dayOffset < 14 && options.length < 3; dayOffset++) {
    const testDate = torontoToUTC(fromLocal.year, fromLocal.month, fromLocal.day + dayOffset, 10, 0);
    const comps = toTorontoComponents(testDate);
    const dayOfWeek = torontoDayOfWeek(testDate);
    const hours = CLINIC_HOURS[dayOfWeek];
    if (!hours) continue;

    const openMinutes = hours.open * 60;
    const closeMinutes = hours.close * 60;

    for (let minuteOfDay = openMinutes; minuteOfDay + duration <= closeMinutes && options.length < 3; minuteOfDay += stepMinutes) {
      const h = Math.floor(minuteOfDay / 60);
      const m = minuteOfDay % 60;
      const slotStart = torontoToUTC(comps.year, comps.month, comps.day, h, m);
      const slotEnd = new Date(slotStart.getTime() + duration * 60000);
      if (dayOffset === 0 && slotStart.getTime() <= fromUTC.getTime()) continue;
      if (slotStart.getTime() < Date.now()) continue;
      if (withinClinicHours(slotStart, slotEnd) && slotFree(slotStart, slotEnd, bookedSlots, excludeEventId)) {
        options.push({
          datetime: slotStart.toISOString(),
          label: formatSlot(slotStart)
        });
      }
    }
  }
  return options;
}

