function extractPhone(eventJson) {
  const desc = (eventJson.description || "") + " " + JSON.stringify(eventJson.extendedProperties || {});
  const phoneMatch = desc.match(/\+?1?\d{10,11}/);
  if (phoneMatch) return phoneMatch[0].replace(/\D/g, "").slice(-10);
  if (eventJson.attendees) {
    for (const a of eventJson.attendees) {
      const aMatch = ((a.displayName || "") + " " + (a.email || "")).match(/\+?1?\d{10,11}/);
      if (aMatch) return aMatch[0].replace(/\D/g, "").slice(-10);
    }
  }
  return "";
}

function normalizePhone(p) {
  return (p || "").replace(/\D/g, "").slice(-10);
}

const allEvents = $input.all()
  .filter(e => e.json.start && e.json.end)
  .map(e => ({
    id: e.json.id,
    summary: e.json.summary || "",
    description: e.json.description || "",
    start: new Date(e.json.start.dateTime || e.json.start.date),
    end: new Date(e.json.end.dateTime || e.json.end.date),
    phone: extractPhone(e.json)
  }));

