  matchedEvent = allEvents.find(e =>
    normalizePhone(e.phone) === callerPhone &&
    Math.abs(e.start.getTime() - oldTime) < TOLERANCE_MS
  );
}

// Fallback: time only
if (!matchedEvent && oldTime) {
  matchedEvent = allEvents.find(e =>
    Math.abs(e.start.getTime() - oldTime) < TOLERANCE_MS
  );
}

// Fallback: phone only — nearest future appointment
if (!matchedEvent && callerPhone) {
  const now = Date.now();
  const phoneMatches = allEvents
    .filter(e => normalizePhone(e.phone) === callerPhone && e.start.getTime() > now)
    .sort((a, b) => a.start.getTime() - b.start.getTime());
  if (phoneMatches.length === 1) {
    matchedEvent = phoneMatches[0];
  } else if (phoneMatches.length > 1 && oldTime) {
    matchedEvent = phoneMatches.reduce((best, e) =>
      Math.abs(e.start.getTime() - oldTime) < Math.abs(best.start.getTime() - oldTime) ? e : best
    );
  }
}

