  let message;
  if (alternatives.length > 0) {
    const labels = alternatives.map(a => a.label);
    if (labels.length === 1) {
      message = "That's outside our office hours. The nearest opening I have is " + labels[0] + ".";
    } else if (labels.length === 2) {
      message = "That's outside our office hours. I can offer " + labels[0] + " or " + labels[1] + ".";
    } else {
      message = "That's outside our office hours. I can do " + labels[0] + ", " + labels[1] + ", or " + labels[2] + " — which works best?";
