  1: { open: 9, close: 19 }, // Monday
  2: { open: 9, close: 17 }, // Tuesday
  3: { open: 9, close: 17 }, // Wednesday
  4: { open: 9, close: 17 }, // Thursday
  5: null,                   // Friday CLOSED
  6: { open: 9, close: 15 }, // Saturday
  0: null                    // Sunday CLOSED
};
function getDayOfWeek(dateStr) {
  const [y, m, d] = dateStr.split('-').map(Number);
  return new Date(y, m - 1, d).getDay();
}

function formatSlot(date) {
  return date.toLocaleString("en-CA", {
    timeZone: "America/Toronto",
    weekday: "long",
    month: "long",
    day: "numeric",
    hour: "numeric",
    minute: "2-digit",
    hour12: true
  });
}

function overlaps(startA, endA, startB, endB) {
  return startA < endB && endA > startB;
}

const input = $('Get available slots - process input').first().json;
const requestedDate = input.requested_date;
const timePreference = String(input.time_preference || '').toLowerCase();
const duration = input.duration_minutes || 60;
const weekday = getDayOfWeek(requestedDate);
const hours = CLINIC_HOURS[weekday];

if (!hours) {
  return [{
    json: {
      success: false,
      slots: [],
      message: "The clinic is closed that day."
    }
  }];
}

const bookedEvents = items
  .filter(item => item.json.start && item.json.end)
  .map(item => ({
    start: new Date(item.json.start.dateTime || item.json.start.date),
    end: new Date(item.json.end.dateTime || item.json.end.date)
  }));

let startHour = hours.open;
let endHour = hours.close;

if (timePreference.includes("morning")) {
  startHour = Math.max(startHour, 10);
  endHour = Math.min(endHour, 12);
} else if (timePreference.includes("afternoon")) {
  startHour = Math.max(startHour, 12);
  endHour = Math.min(endHour, 17);
} else if (timePreference.includes("evening")) {
  startHour = Math.max(startHour, 17);
}

const slots = [];
const stepMinutes = duration;
const totalStartMinutes = startHour * 60;
const totalEndMinutes = endHour * 60;

for (let minutes = totalStartMinutes; minutes < totalEndMinutes; minutes += stepMinutes) {
  const hour = Math.floor(minutes / 60);
  const minute = minutes % 60;
  const slotStart = new Date(
    `${requestedDate}T${String(hour).padStart(2, '0')}:${String(minute).padStart(2, '0')}:00-04:00`
  );
  const slotEnd = new Date(slotStart.getTime() + duration * 60000);
  const closeTime = new Date(
    `${requestedDate}T${String(endHour).padStart(2, '0')}:00:00-04:00`
  );

  if (slotEnd > closeTime) continue;

  const conflict = bookedEvents.some(event =>
    overlaps(slotStart, slotEnd, event.start, event.end)
  );

  if (!conflict) {
    slots.push({
      datetime: slotStart.toISOString(),
      label: formatSlot(slotStart)
    });
  }

  if (slots.length >= 5) break;
}

let message = "I'm not finding any openings that day.";
if (slots.length === 1) {
  message = `I have ${slots[0].label} available.`;
} else if (slots.length === 2) {
  message = `I have ${slots[0].label} or ${slots[1].label} available.`;
} else if (slots.length >= 3) {
  message = `I have ${slots[0].label}, ${slots[1].label}, or ${slots[2].label} available.`;
}

return [{
